local TD = TD.td1madao["ydj_dst_td1madao"] local myComponent = Class(function(self, inst)     self.inst = inst     self.taskList = {}     self.time = 0     self.buffer = {}     self.bak = {}     self.task = self.inst:DoPeriodicTask(1, function()         for i, v in pairs(self.taskList) do             local myTask = self.taskList[i]             if myTask and myTask.run and myTask.period and self.time % myTask.period == 0 then                 myTask.run()             end         end         self.bak = self.buffer         self.buffer = {}         self.time = self.time + 1         if self.time > 86400 then             self.time = 0         end     end) end) function myComponent:common_addTask(name, run, period)     self:common_removeTask(name)     self:common_removeTask(name)     if self.taskList then         self.taskList[name] = {}         self.taskList[name].run = run         self.taskList[name].period = period     end end function myComponent:common_removeTask(name)     if self.taskList and self.taskList[name] then         self.taskList[name].run = nil         self.taskList[name].period = nil         self.taskList[name] = nil     end end function myComponent:common_hasTask(name)     return self.taskList and self.taskList[name] and self.taskList[name].run end function myComponent:player_addTask(name, run, period)     self:common_addTask(name, run, period) end function myComponent:server_addTask(name, run, period)     self:common_addTask(name, run, period) end function myComponent:player_hasTask(name)     return self:common_hasTask(name) end function myComponent:server_hasTask(name)     return self:common_hasTask(name) end function myComponent:player_removeTask(name)     self:common_removeTask(name) end function myComponent:server_removeTask(name)     self:common_removeTask(name) end return myComponent 